import{d as n,r as l,c as v,a as s,b as e,w as d,e as o,o as c,f as t,p as f,g as p,_ as r}from"./index-95246ce0.js";const g=i=>(f("data-v-91dfe066"),i=i(),p(),i),u={class:"culture-detail-page"},_={class:"home-header"},h=g(()=>s("div",{class:"logo"},[s("h1",null,"山河桥语"),s("p",null,"中国古代桥梁时空数据可视化")],-1)),m={class:"nav-menu"},b=o('<main class="detail-content" data-v-91dfe066><section class="detail-header" data-v-91dfe066><h2 data-v-91dfe066>安平桥</h2><p data-v-91dfe066>中国古代最长的石桥</p></section><section class="detail-section" data-v-91dfe066><div class="section-content" data-v-91dfe066><h3 data-v-91dfe066>基本信息</h3><div class="info-grid" data-v-91dfe066><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>中文名</span><span class="info-value" data-v-91dfe066>安平桥</span></div><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>别名</span><span class="info-value" data-v-91dfe066>五里桥、西桥</span></div><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>地理位置</span><span class="info-value" data-v-91dfe066>福建省泉州市晋江市安海镇</span></div><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>建造时间</span><span class="info-value" data-v-91dfe066>南宋绍兴八年（1138年）</span></div><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>建成时间</span><span class="info-value" data-v-91dfe066>南宋绍兴二十二年（1152年）</span></div><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>桥梁类型</span><span class="info-value" data-v-91dfe066>梁式石桥</span></div><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>桥梁长度</span><span class="info-value" data-v-91dfe066>2255米</span></div><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>桥梁宽度</span><span class="info-value" data-v-91dfe066>3-3.8米</span></div><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>桥墩数量</span><span class="info-value" data-v-91dfe066>361个</span></div><div class="info-item" data-v-91dfe066><span class="info-label" data-v-91dfe066>保护级别</span><span class="info-value" data-v-91dfe066>全国重点文物保护单位</span></div></div></div></section><section class="detail-section" data-v-91dfe066><div class="section-content" data-v-91dfe066><h3 data-v-91dfe066>历史沿革</h3><p data-v-91dfe066>安平桥始建于南宋绍兴八年（1138年），由泉州知州赵令衿主持建造，建成于南宋绍兴二十二年（1152年）。</p><p data-v-91dfe066>在历史上，安平桥经历了多次修缮：</p><ul data-v-91dfe066><li data-v-91dfe066><strong data-v-91dfe066>明永乐年间（1403-1424年）</strong>：进行了修缮。</li><li data-v-91dfe066><strong data-v-91dfe066>明正统年间（1436-1449年）</strong>：进行了大规模的修缮。</li><li data-v-91dfe066><strong data-v-91dfe066>清康熙年间（1662-1722年）</strong>：进行了修缮。</li><li data-v-91dfe066><strong data-v-91dfe066>清乾隆年间（1736-1795年）</strong>：进行了修缮。</li><li data-v-91dfe066><strong data-v-91dfe066>1980-1985年</strong>：对安平桥进行了全面的修缮，恢复了其历史原貌。</li><li data-v-91dfe066><strong data-v-91dfe066>2006-2010年</strong>：对安平桥进行了再次修缮，加强了桥梁的安全性。</li></ul></div></section><section class="detail-section" data-v-91dfe066><div class="section-content" data-v-91dfe066><h3 data-v-91dfe066>建筑特色</h3><p data-v-91dfe066>安平桥是中国古代最长的石桥，其建筑特色主要体现在以下几个方面：</p><h4 data-v-91dfe066>1. 长度与规模</h4><p data-v-91dfe066>安平桥全长2255米，是中国古代最长的石桥，被誉为&quot;天下无桥长此桥&quot;。桥梁共有361个桥墩，362个桥孔，规模宏大。</p><h4 data-v-91dfe066>2. 桥墩设计</h4><p data-v-91dfe066>安平桥的桥墩设计独特，采用了长方形、船形和半船形三种形式。船形桥墩可以减少水流对桥墩的冲击力，增强桥梁的稳定性。</p><h4 data-v-91dfe066>3. 石材选用</h4><p data-v-91dfe066>安平桥的石材选用了当地的花岗岩，这种石材坚硬耐用，能够承受长期的风吹浪打。桥梁的石梁长10米左右，重约5吨，体现了古代工匠的搬运和架设能力。</p><h4 data-v-91dfe066>4. 桥亭与碑刻</h4><p data-v-91dfe066>安平桥上建有五座桥亭，分别是水心亭、中亭、宫亭、雨亭和楼亭。这些桥亭不仅是行人休息的场所，也是桥梁的装饰。桥上还保存有许多碑刻，记载了桥梁的建造和修缮历史。</p></div></section><section class="detail-section" data-v-91dfe066><div class="section-content" data-v-91dfe066><h3 data-v-91dfe066>历史意义</h3><p data-v-91dfe066>安平桥在中国桥梁史上具有重要的历史意义：</p><ul data-v-91dfe066><li data-v-91dfe066>它是中国古代最长的石桥，体现了中国古代桥梁建筑的高超技艺。</li><li data-v-91dfe066>它是泉州海上丝绸之路的重要组成部分，见证了泉州作为海上丝绸之路起点的繁荣。</li><li data-v-91dfe066>它是中国古代科技成就的重要代表，被列为全国重点文物保护单位。</li><li data-v-91dfe066>它是中国古代桥梁建筑的杰出典范，对后世桥梁建设产生了深远影响。</li></ul></div></section><section class="detail-section" data-v-91dfe066><div class="section-content" data-v-91dfe066><h3 data-v-91dfe066>文化内涵</h3><p data-v-91dfe066>安平桥不仅是一座实用的交通设施，也是中国传统文化的重要象征：</p><h4 data-v-91dfe066>1. 民间传说</h4><p data-v-91dfe066>关于安平桥的建造，民间流传着许多传说。其中最著名的是&quot;神仙助建&quot;的故事：相传安平桥的建造得到了神仙的帮助，一夜之间就完成了桥梁的建设。</p><h4 data-v-91dfe066>2. 碑刻与题字</h4><p data-v-91dfe066>安平桥上保存有许多碑刻和题字，其中最著名的是&quot;天下无桥长此桥&quot;的题字，表达了人们对安平桥长度的惊叹。</p><h4 data-v-91dfe066>3. 民俗活动</h4><p data-v-91dfe066>每年的农历三月初三，安平桥周边会举行盛大的民俗活动，如踩桥、祈愿等，体现了当地人民对安平桥的敬仰和崇拜。</p></div></section><section class="detail-section" data-v-91dfe066><div class="section-content" data-v-91dfe066><h3 data-v-91dfe066>桥梁图片</h3><div class="image-gallery" data-v-91dfe066><img src="https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Anping%20Bridge%20ancient%20stone%20bridge%20in%20Quanzhou%2C%20Fujian%2C%20Song%20Dynasty%2C%20historical%20landmark%2C%20long%20stone%20bridge&amp;image_size=landscape_16_9" alt="安平桥全景" class="gallery-image" data-v-91dfe066><img src="https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Anping%20Bridge%20piers%20close%20up%2C%20ancient%20Chinese%20bridge%2C%20stone%20structure&amp;image_size=landscape_16_9" alt="安平桥桥墩" class="gallery-image" data-v-91dfe066><img src="https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Anping%20Bridge%20pavilion%2C%20ancient%20Chinese%20bridge%2C%20historical%20architecture&amp;image_size=landscape_16_9" alt="安平桥亭" class="gallery-image" data-v-91dfe066></div></div></section></main><footer class="page-footer" data-v-91dfe066><p data-v-91dfe066>© 2026 山河桥语 - 中国古代桥梁时空数据可视化</p></footer>',2),C=n({__name:"BridgeAnpingPage",setup(i){return(x,B)=>{const a=l("router-link");return c(),v("div",u,[s("header",_,[h,s("nav",m,[e(a,{to:"/",class:"nav-item"},{default:d(()=>[t("首页")]),_:1}),e(a,{to:"/visualization",class:"nav-item"},{default:d(()=>[t("数据可视化")]),_:1}),e(a,{to:"/culture",class:"nav-item active"},{default:d(()=>[t("文化介绍")]),_:1}),e(a,{to:"/statistics",class:"nav-item"},{default:d(()=>[t("数据统计")]),_:1}),e(a,{to:"/about",class:"nav-item"},{default:d(()=>[t("关于项目")]),_:1})])]),b])}}});const q=r(C,[["__scopeId","data-v-91dfe066"]]);export{q as default};
